   153	            builder.AddAttribute(8, "oncontextmenu", EventCallback.Factory.Create<MouseEventArgs>(this, OnTriggerContextMenu));
   154	            builder.AddEventPreventDefaultAttribute(9, "oncontextmenu", true);
   155	        }
   156	
   157	        if (IsTriggerTouchStart())
   158	        {
   159	            builder.AddAttribute(10, "ontouchstart", OnTouchStart);
   160	        }
   161	
   162	        if (IsTriggerTouchEnd())
   163	        {
   164	            builder.AddAttribute(11, "ontouchend", OnTouchEnd);
   165	        }
   166	
   167	        builder.AddContent(12, ChildContent);
   168	
   169	        if (generateElement)
   170	        {
   171	            builder.CloseElement();
   172	        }
   173	    }
   174	
   175	    private bool ShouldGenerateElement() => GenerateElement || IsTriggerClick() || IsTriggerDoubleClick() || IsTriggerTouchStart() || IsTriggerTouchEnd();
   176	
   177	    private bool IsTriggerClick() => TriggerClick && OnClick != null;
   178	
   179	    private bool IsTriggerDoubleClick() => TriggerDoubleClick && OnDoubleClick != null;
   180	
   181	    private bool IsTriggerContextMenu() => TriggerContextMenu && OnContextMenu != null;
   182	
   183	    private bool IsTriggerTouchStart() => OnTouchStart.HasDelegate;
   184	
   185	    private bool IsTriggerTouchEnd() => OnTouchEnd.HasDelegate;
   186	
   187	    private async Task OnTriggerClick()
   188	    {
   189	        if (OnClick != null)
   190	        {
   191	            await OnClick();
   192	        }
   193	    }
   194	
   195	    private async Task OnTriggerDoubleClick()
   196	    {
   197	        if (OnDoubleClick != null)
   198	        {
   199	            await OnDoubleClick();
   200	        }
   201	    }
   202	
   203	    private async Task OnTriggerContextMenu(MouseEventArgs e)
   204	    {
   205	        if (OnContextMenu != null)
   206	        {
   207	            await OnContextMenu(e);
   208	        }
   209	    }
